import React from 'react';
import { StyleSheet, Text, View } from 'react-native';
import { ORDER_STATUS_META, ORDER_STATUS_STEPS } from '../data/orderModule';
import { OrderStatus } from '../services/firebaseService';

type OrderStatusTrackerProps = {
  status: OrderStatus;
  compact?: boolean;
};

const OrderStatusTracker = ({ status, compact }: OrderStatusTrackerProps) => {
  const activeIndex = ORDER_STATUS_STEPS.findIndex((step) => step.id === status);

  if (status === 'cancelled') {
    return (
      <View style={styles.cancelledCard}>
        <Text style={styles.cancelledTitle}>Order cancelled</Text>
        <Text style={styles.cancelledText}>This order was cancelled before delivery.</Text>
      </View>
    );
  }

  const compactActiveIndex = ORDER_STATUS_STEPS.findIndex((step) => step.id === status);

  if (compact) {
    return (
      <View style={[styles.card, styles.cardCompact]}>
        <View style={styles.compactRow}>
          {ORDER_STATUS_STEPS.map((step, index) => {
            const isActive = index <= compactActiveIndex;
            const meta = ORDER_STATUS_META[step.id];
            const title =
              step.id === 'out_for_delivery'
                ? 'Out for\nDelivery'
                : step.shortLabel;

            return (
              <View key={step.id} style={styles.compactStep}>
                <View style={styles.compactTrackRow}>
                  <View
                    style={[
                      styles.dot,
                      styles.compactDot,
                      {
                        backgroundColor: isActive ? meta.accent : '#D7E6F1'
                      }
                    ]}
                  />
                  {index < ORDER_STATUS_STEPS.length - 1 ? (
                    <View style={[styles.compactLine, isActive && styles.lineActive]} />
                  ) : null}
                </View>
                <Text style={[styles.compactTitle, isActive && styles.stepTitleActive]}>
                  {title}
                </Text>
              </View>
            );
          })}
        </View>
      </View>
    );
  }

  return (
    <View style={styles.card}>
      {ORDER_STATUS_STEPS.map((step, index) => {
        const isActive = index <= activeIndex;
        const meta = ORDER_STATUS_META[step.id];
        return (
          <View key={step.id} style={styles.stepRow}>
            <View style={styles.trackColumn}>
              <View
                style={[
                  styles.dot,
                  {
                    backgroundColor: isActive ? meta.accent : '#D7E6F1'
                  }
                ]}
              />
              {index < ORDER_STATUS_STEPS.length - 1 ? (
                <View style={[styles.line, isActive && styles.lineActive]} />
              ) : null}
            </View>
            <View style={styles.textColumn}>
              <Text style={[styles.stepTitle, isActive && styles.stepTitleActive]}>
                {step.label}
              </Text>
              <Text style={styles.stepSubtitle}>
                {isActive ? 'Completed' : 'Waiting for update'}
              </Text>
            </View>
          </View>
        );
      })}
    </View>
  );
};

const styles = StyleSheet.create({
  card: {
    backgroundColor: 'white',
    borderRadius: 24,
    padding: 18
  },
  cardCompact: {
    paddingTop: 10,
    paddingBottom: 12
  },
  compactRow: {
    flexDirection: 'row',
    alignItems: 'flex-start'
  },
  compactStep: {
    flex: 1,
    minWidth: 0
  },
  compactTrackRow: {
    flexDirection: 'row',
    alignItems: 'center'
  },
  compactDot: {
    marginTop: 0
  },
  compactLine: {
    flex: 1,
    height: 3,
    borderRadius: 999,
    backgroundColor: '#D7E6F1',
    marginHorizontal: 4
  },
  compactTitle: {
    marginTop: 7,
    color: '#547185',
    fontSize: 10,
    fontWeight: '700',
    textAlign: 'center',
    lineHeight: 12,
    minHeight: 34,
    paddingHorizontal: 1
  },
  stepRow: {
    flexDirection: 'row'
  },
  trackColumn: {
    width: 24,
    alignItems: 'center'
  },
  dot: {
    width: 14,
    height: 14,
    borderRadius: 7,
    marginTop: 4
  },
  line: {
    width: 3,
    flex: 1,
    borderRadius: 999,
    backgroundColor: '#D7E6F1',
    marginVertical: 4
  },
  lineActive: {
    backgroundColor: '#7ED1F5'
  },
  textColumn: {
    flex: 1,
    paddingBottom: 14,
    paddingLeft: 10
  },
  stepTitle: {
    color: '#547185',
    fontSize: 16,
    fontWeight: '700'
  },
  stepTitleActive: {
    color: '#10324A'
  },
  stepSubtitle: {
    marginTop: 4,
    color: '#7B95A6',
    fontSize: 12
  },
  cancelledCard: {
    backgroundColor: '#FEE2E2',
    borderRadius: 24,
    padding: 18
  },
  cancelledTitle: {
    color: '#B42318',
    fontSize: 18,
    fontWeight: '800'
  },
  cancelledText: {
    marginTop: 6,
    color: '#B42318',
    fontSize: 13,
    lineHeight: 19
  }
});

export default OrderStatusTracker;
