import { initializeApp } from 'firebase/app';
import { connectAuthEmulator, getAuth } from 'firebase/auth';
import { connectFirestoreEmulator, getFirestore, initializeFirestore, setLogLevel } from 'firebase/firestore';

setLogLevel('silent');

const firebaseConfig = {
  apiKey: "AIzaSyBSI0Owxy5JXail-bnjuPO-Gg2Gr3TtGac",
  authDomain: "watercan-b4182.firebaseapp.com",
  projectId: "watercan-b4182",
  storageBucket: "watercan-b4182.firebasestorage.app",
  messagingSenderId: "744935575489",
  appId: "1:744935575489:web:cf64a72d95794ce2c62940",
  measurementId: "G-PYRYLSP6TL"
};

export { firebaseConfig };
export const firebaseApp = initializeApp(firebaseConfig);

const createAuth = () => {
  return getAuth(firebaseApp);
};

const createDb = () => {
  try {
    return initializeFirestore(firebaseApp, {
      experimentalAutoDetectLongPolling: true
    });
  } catch {
    return getFirestore(firebaseApp);
  }
};

export const auth = createAuth();
export const db = createDb();

const useEmulators = process.env.EXPO_PUBLIC_USE_EMULATORS === 'true';
const emulatorHost = process.env.EXPO_PUBLIC_FIREBASE_EMULATOR_HOST || '127.0.0.1';

if (useEmulators) {
  connectAuthEmulator(auth, `http://${emulatorHost}:9099`, { disableWarnings: true });
  connectFirestoreEmulator(db, emulatorHost, 8080);
}

export default firebaseApp;
