import { useFocusEffect, useNavigation } from '@react-navigation/native';
import { NativeStackNavigationProp } from '@react-navigation/native-stack';
import React, { useCallback, useContext, useState } from 'react';
import { Alert, ImageBackground, Modal, Pressable, SafeAreaView, ScrollView, StyleSheet, Text, TextInput, View } from 'react-native';
import { AuthContext } from '../../App';
import AppIcon from '../components/AppIcon';
import CustomerBottomNav from '../components/CustomerBottomNav';
import OrderStatusTracker from '../components/OrderStatusTracker';
import PaymentOptionCard from '../components/PaymentOptionCard';
import { formatCurrency, formatOrderNumber, PAYMENT_OPTIONS, WATER_PRODUCT } from '../data/orderModule';
import { useLang } from '../i18n/LanguageContext';
import { RootStackParamList } from '../navigation/AppNavigator';
import {
  autoProgressOrders,
  createOrder,
  fetchInventorySummary,
  getFriendlyOrderMessage,
  OrderRecord,
  subscribeToCustomerOrders
} from '../services/firebaseService';
import waterCanImage from '../assets/20-l-water-can1.jpg';

type NavigationProp = NativeStackNavigationProp<RootStackParamList, 'CustomerHome'>;
type PaymentMethod = (typeof PAYMENT_OPTIONS)[number]['id'];
type OrderModalMode = 'repeat' | 'payment' | null;

const defaultUpiId = 'thannican@upi';

const CustomerHomeScreen = () => {
  const { profile } = useContext(AuthContext);
  const { t } = useLang();
  const navigation = useNavigation<NavigationProp>();
  const [orders, setOrders] = useState<OrderRecord[]>([]);
  const [liveStock, setLiveStock] = useState(WATER_PRODUCT.availableStock);
  const [quantity, setQuantity] = useState(1);
  const [ordering, setOrdering] = useState(false);
  const [orderSuccess, setOrderSuccess] = useState<{ orderNumber?: number } | null>(null);
  const [orderModalMode, setOrderModalMode] = useState<OrderModalMode>(null);
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('Cash on Delivery');
  const [upiId, setUpiId] = useState(defaultUpiId);

  useFocusEffect(
    useCallback(() => {
      let active = true;
      let unsubscribeOrders: (() => void) | undefined;

      const load = async () => {
        if (!profile?.uid) {
          setOrders([]);
          return;
        }

        const refreshStock = async () => {
          const inv = await fetchInventorySummary().catch(() => null);
          if (!active || !inv) {
            return;
          }

          setLiveStock(Math.max(0, (inv.openingStock ?? 0) + (inv.restockedCans ?? 0) - (inv.soldCans ?? 0)));
        };

        await autoProgressOrders(profile.uid).catch(() => {});

        unsubscribeOrders = subscribeToCustomerOrders(profile.uid, (data) => {
          if (active) {
            setOrders(data);
            refreshStock();
          }
        });

        await refreshStock();
      };

      load();

      return () => {
        active = false;
        unsubscribeOrders?.();
      };
    }, [profile?.uid])
  );

  const countedOrders = orders.filter((order) => order.status !== 'cancelled');
  const activeOrders = countedOrders.filter((order) => order.status !== 'delivered');
  const activeOrder = activeOrders[0] ?? null;

  const validateOrder = () => {
    if (!profile) {
      Alert.alert(t.orderFailed, 'Please sign in again.');
      return false;
    }
    if (profile.role !== 'customer') {
      Alert.alert(t.orderFailed, 'Only customer accounts can place new orders.');
      return false;
    }
    if (!profile.approved) {
      Alert.alert(t.orderFailed, 'Your account is waiting for approval. Please contact the owner before placing an order.');
      return false;
    }
    if (!profile.address?.trim()) {
      Alert.alert(t.orderFailed, 'Please add your delivery address in Profile before placing an order.');
      navigation.navigate('Profile');
      return false;
    }
    if (liveStock <= 0) {
      Alert.alert(t.orderFailed, 'Water cans are currently out of stock.');
      return false;
    }
    if (quantity > liveStock) {
      Alert.alert(t.orderFailed, `Only ${liveStock} cans are available right now.`);
      return false;
    }
    return true;
  };

  const submitOrder = async () => {
    if (!validateOrder() || !profile) {
      return;
    }
    if (paymentMethod === 'UPI ID' && !upiId.trim()) {
      Alert.alert(t.orderFailed, 'Please enter a valid UPI ID.');
      return;
    }

    setOrdering(true);
    try {
      const selectedPaymentMethod = paymentMethod === 'UPI ID' ? `UPI ID (${upiId.trim()})` : paymentMethod;
      const result = await createOrder({
        customerId: profile.uid,
        customerName: profile.name,
        phone: profile.phone,
        address: profile.address?.trim() || '',
        productName: WATER_PRODUCT.name,
        quantity,
        pricePerCan: WATER_PRODUCT.pricePerCan,
        deliveryCharge: 0,
        totalAmount: quantity * WATER_PRODUCT.pricePerCan,
        availableStock: liveStock,
        note: '',
        paymentMethod: selectedPaymentMethod,
        paymentStatus: paymentMethod === 'Cash on Delivery' ? 'unpaid' : 'paid',
        paidAmount: paymentMethod === 'Cash on Delivery' ? 0 : quantity * WATER_PRODUCT.pricePerCan,
        deliverySlot: 'Morning',
        expectedDeliveryTime: '7:00 AM - 10:00 AM',
        subscription: false
      });
      setOrders((current) => {
        const nextOrder = result as OrderRecord;
        return current.some((order) => order.id === nextOrder.id)
          ? current
          : [nextOrder, ...current];
      });
      setLiveStock((current) => Math.max(0, current - quantity));
      setOrderSuccess({ orderNumber: result.orderNumber });
      setOrderModalMode(null);
      setTimeout(() => setOrderSuccess(null), 3500);
    } catch (e: any) {
      Alert.alert(t.orderFailed, getFriendlyOrderMessage(e));
    } finally {
      setOrdering(false);
    }
  };

  const handleOrder = async () => {
    if (!validateOrder()) {
      return;
    }
    if (activeOrder) {
      setOrderModalMode('repeat');
      return;
    }

    setOrderModalMode('payment');
  };

  const handleOrderAgain = async () => {
    setOrderModalMode('payment');
  };

  return (
    <SafeAreaView style={styles.container}>
      <Modal
        visible={orderModalMode !== null}
        transparent
        animationType="fade"
        onRequestClose={() => setOrderModalMode(null)}
      >
        <View style={styles.modalOverlay}>
          <View style={styles.modalCard}>
            {orderModalMode === 'repeat' ? (
              <>
                <Text style={styles.modalTitle}>You have already placed an order. Do you want to place again?</Text>
                <View style={styles.modalActions}>
                  <Pressable style={styles.modalSecondaryButton} onPress={() => setOrderModalMode(null)}>
                    <Text style={styles.modalSecondaryButtonText}>Close</Text>
                  </Pressable>
                  <Pressable
                    style={[styles.modalPrimaryButton, ordering && styles.disabledButton]}
                    onPress={handleOrderAgain}
                    disabled={ordering}
                  >
                    <Text style={styles.modalPrimaryButtonText}>{ordering ? t.placingOrder : 'Order Again'}</Text>
                  </Pressable>
                </View>
              </>
            ) : (
              <>
                <Text style={styles.modalTitle}>Choose payment method</Text>
                <Text style={styles.modalSubtitle}>Total payable: {formatCurrency(quantity * WATER_PRODUCT.pricePerCan)}</Text>
                <View style={styles.paymentList}>
                  {PAYMENT_OPTIONS.map((option) => (
                    <PaymentOptionCard
                      key={option.id}
                      title={option.title}
                      subtitle={option.subtitle}
                      selected={paymentMethod === option.id}
                      onPress={() => setPaymentMethod(option.id)}
                    />
                  ))}
                </View>
                {paymentMethod === 'UPI ID' ? (
                  <View style={styles.upiBox}>
                    <Text style={styles.upiLabel}>UPI ID</Text>
                    <TextInput
                      style={styles.upiInput}
                      value={upiId}
                      onChangeText={setUpiId}
                      placeholder={defaultUpiId}
                      placeholderTextColor="#7B93AA"
                    />
                  </View>
                ) : null}
                {paymentMethod === 'Google Pay' ? (
                  <View style={styles.upiBox}>
                    <Text style={styles.upiLabel}>Google Pay</Text>
                    <Text style={styles.upiHelp}>Send payment to {defaultUpiId} using Google Pay.</Text>
                  </View>
                ) : null}
                <View style={styles.modalActions}>
                  <Pressable style={styles.modalSecondaryButton} onPress={() => setOrderModalMode(null)}>
                    <Text style={styles.modalSecondaryButtonText}>Back</Text>
                  </Pressable>
                  <Pressable
                    style={[styles.modalPrimaryButton, ordering && styles.disabledButton]}
                    onPress={submitOrder}
                    disabled={ordering}
                  >
                    <Text style={styles.modalPrimaryButtonText}>{ordering ? t.placingOrder : 'Place Order'}</Text>
                  </Pressable>
                </View>
              </>
            )}
          </View>
        </View>
      </Modal>

      <ScrollView contentContainerStyle={styles.content} showsVerticalScrollIndicator={false}>

        <View style={styles.header}>
          <View>
            <Text style={styles.greeting}>{t.hello}, {profile?.name?.split(' ')[0] || t.customer}</Text>
            <Text style={styles.appName}>{t.appName}</Text>
          </View>
          <Pressable style={styles.profileButton} onPress={() => navigation.navigate('Profile')}>
            <AppIcon name="person" size={20} color="#0F6CBD" />
          </Pressable>
        </View>

        {orderSuccess ? (
          <View style={styles.successBanner}>
            <AppIcon name="checkmark-circle" size={20} color="#1E7A45" />
            <View style={styles.successCopy}>
              <Text style={styles.successTitle}>Order Successful</Text>
              <Text style={styles.successText}>
                {orderSuccess.orderNumber ? `Order ${formatOrderNumber(orderSuccess)} is now being tracked below.` : 'Your order is now being tracked below.'}
              </Text>
            </View>
            <Pressable style={styles.successClose} onPress={() => setOrderSuccess(null)}>
              <Text style={styles.successCloseText}>×</Text>
            </Pressable>
          </View>
        ) : null}

        {/* Horizontal tracking bar */}
        {activeOrder ? (
          <View style={styles.trackBar}>
            <View style={styles.trackHeader}>
              <Text style={styles.trackLabelText}>Tracking {formatOrderNumber(activeOrder)}</Text>
            </View>
            <OrderStatusTracker status={activeOrder.status} compact />
          </View>
        ) : (
          <View style={styles.noOrderBar}>
            <AppIcon name="water-outline" size={18} color="#7B93AA" />
            <Text style={styles.noOrderText}>No water can order placed</Text>
          </View>
        )}

        {/* Product details */}
        <View style={styles.card}>
          <View style={styles.sectionHeader}>
            <View>
              <Text style={styles.sectionTitle}>Product details</Text>
              <Text style={styles.sectionSubtitle}>Single can home delivery</Text>
            </View>
            <Text style={styles.price}>{formatCurrency(WATER_PRODUCT.pricePerCan)}</Text>
          </View>
          <View style={styles.detailsGrid}>
            <View style={styles.detailBlock}>
              <Text style={styles.detailLabel}>Stock</Text>
              <Text style={styles.detailValue}>{liveStock} cans</Text>
            </View>
            <View style={styles.detailBlock}>
              <Text style={styles.detailLabel}>Orders</Text>
              <Text style={styles.detailValue}>{activeOrders.length}</Text>
            </View>
          </View>
        </View>

        <ImageBackground source={waterCanImage} resizeMode="contain" imageStyle={styles.bgCanImage} style={styles.heroCard}>
          <View style={styles.bgWash} />
          <View style={styles.heroQuantityOverlay}>
            <Pressable style={styles.stepperButton} onPress={() => setQuantity((q) => Math.max(1, q - 1))}>
              <Text style={styles.stepperText}>-</Text>
            </Pressable>
            <View style={styles.quantityValueWrap}>
              <Text style={styles.quantityValue}>{quantity}</Text>
              <Text style={styles.quantityHint}>cans</Text>
            </View>
            <Pressable style={styles.stepperButton} onPress={() => setQuantity((q) => Math.min(liveStock, q + 1))}>
              <Text style={styles.stepperText}>+</Text>
            </Pressable>
          </View>
        </ImageBackground>

        <View style={styles.card}>
          <View style={styles.totalRow}>
            <Text style={styles.totalLabel}>Total</Text>
            <Text style={styles.totalValue}>{formatCurrency(quantity * WATER_PRODUCT.pricePerCan)}</Text>
          </View>
          <Pressable style={[styles.orderButton, ordering && styles.disabledButton]} onPress={handleOrder} disabled={ordering}>
            <Text style={styles.orderButtonText}>
              {ordering ? t.placingOrder : `Order ${quantity} Can${quantity > 1 ? 's' : ''}`}
            </Text>
          </Pressable>
        </View>
      </ScrollView>

      <CustomerBottomNav active="CustomerHome" />
    </SafeAreaView>
  );
};

